test_that("dmta.height works", {
    
  tmp <- tempdir()
  sur <- system.file("tests/sur/test_surf.sur", package = "trident")

  ResHgt <- dmta.height(sur = sur, TmpDir = tmp, size.x = 256,
                                                 size.y = 256, size.n = 256, type = "single")
  
  expect_type(ResHgt, "list")
  
  expect_named(ResHgt, c("File", "Type", "Sa", "Sp", "Sq", "Sv", "Ssk", "Sku", "Sdar", "Sm", "Smd"))
  
  expect_equal(ResHgt$File, basename(sur))
  expect_equal(ResHgt$Type, "height")
  expect_type(ResHgt$Sa,    "double")
  expect_type(ResHgt$Sp,    "double")
  expect_type(ResHgt$Sq,    "double")
  expect_type(ResHgt$Sv,    "double")
  expect_type(ResHgt$Ssk,   "double")
  expect_type(ResHgt$Sku,   "double") 
  expect_type(ResHgt$Sdar,  "double")
  expect_type(ResHgt$Sm,    "double")
  expect_type(ResHgt$Smd,   "double")
  
  ResHgtMulti <- dmta.height(sur = sur, TmpDir = tmp, size.x = 256,
                                                      size.y = 256, size.n = 256, type = "multi")
  
  expect_type(ResHgtMulti, "list")
  
  expect_named(ResHgtMulti, c("File", "Type", "Sa", "Sp", "Sq", "Sv", "Ssk", "Sku",
                                              "Sdar", "Sm", "Smd"))
  
  expect_equal(ResHgtMulti$File, basename(sur))
  expect_equal(ResHgtMulti$Type, "height")

  numeric_fields  <- c("Sa","Sp","Sq","Sv","Ssk","Sku","Sdar","Sm","Smd")
  
  expected_length <- 256
  
  for(i in seq_along(numeric_fields)) {
      
    field <- numeric_fields[i]
    
    expect_type  (ResHgtMulti[[field]], "double")
    expect_length(ResHgtMulti[[field]], expected_length)
    
  }
  
})

