test_that("trident.hetero works", {
   
  x <- c(
    12, 15, NA, 18, 21, -14, NA, 19, 23, 17,
    16, 20, NA, 22, 24,  13, 11, NA, 25, 26,
    27, 28, 29, NA, 30, -10,  9,  8,  7,  6
        ) 
  
  DFstat <- trident.hetero(x, var.name = "ExampleVariable")

    expected <- data.frame(
      min    = -14,
      max    = 30,
      sd     = 11.06014,
      mean   = 16.08,
    
      median = 18,
      fst.05 = -6.8,
      lst.05 = 28.8,
    
      min.05 = -12,
      max.05 = 29.5,
    
      fst.25 = 11,
      lst.25 = 24,
    
      min.25 = 2.428571,
      max.25 = 27,
    
      skw    = -1.09558,
      kurt   = 0.8237028
    )
  
  expect_equal(DFstat, expected, tolerance = 1e-6) # to allow for small numerical differences in the calculations of sd, skewness and kurtosis.

})


test_that("Batch.fun works", {
    
  sur <- system.file("tests/sur/test_surf2.sur", package = "trident")
  
  Mytable <- Batch.fun(sur = sur, size = 256, nCell = 64, peakRemoval = "0",
            doStd = TRUE,
            doComplexity = TRUE, doHeight = TRUE, doSpatial = TRUE, doTopology = TRUE,
            doHComplexity = TRUE, doHHeight = TRUE, doHSpatial = TRUE, doHTopology = TRUE)

  expect_type(Mytable, "list")
  
  vars <- c("Asfc2", "R2adj", "Sa", "Sp", "Sq", "Sv", "Ssk", "Sku", "Sdar", "Sm", "Smd",
            "Rmax", "Sal", "Stri", "Std", "b.sl", "r.sl", "s.sl",
            "Sk1", "Sk2", "Smc1", "Smc2", "Snb1", "Snb2", "Sh")
  
  stats <- c("min","max","sd","mean","median",
             "fst.05","lst.05","min.05","max.05",
             "fst.25","lst.25","min.25","max.25","skw","kurt")
  
  expected_columns <- c("File", vars, vars[-2] %>% purrr::map(~ paste0(.x, ".", stats))
                                                 %>% unlist()) # to generate the expected column names by combining variable names and statistic names with an underscore.
  
  expect_equal(colnames(Mytable), expected_columns)
  
})
